from lxml import etree

def process_soap_request(xml_request):
    # Prevent XML External Entity (XXE) attacks
    parser = etree.XMLParser(resolve_entities=False)
    
    try:
        # Parse the XML request
        root = etree.fromstring(xml_request.encode('utf-8'), parser)
        
        # Validate against DTD if needed (assuming DTD is defined in the XML)
        dtd = etree.DTD('path_to_your_dtd_file.dtd')
        if not dtd.validate(root):
            raise ValueError("XML does not conform to DTD")

        # Extract the SOAP body
        soap_body = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if soap_body is not None:
            return etree.tostring(soap_body, pretty_print=True).decode('utf-8')
        else:
            raise ValueError("SOAP Body not found")
    
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {str(e)}")
    except Exception as e:
        raise ValueError(f"Error processing SOAP request: {str(e)}")